    public Page<INFO> fetchPage(McpRequest mcpRequest, Cursor cursor, int pageSize, JsonObject message) {
        FilterContextImpl filterContext = FilterContextImpl.of(mcpListMethod(), message, mcpRequest);
        if (pageSize <= 0) {
            // Pagination is disabled
            return new Page<>(infosForRequest(filterContext).sorted().toList(), true);
        }
        long count = infosForRequest(filterContext).count();
        if (count == 0) {
            return Page.empty();
        }
        if (count <= pageSize && cursor.isInitial()) {
            // Pagination is not needed for the initial request
            return new Page<>(infosForRequest(filterContext).sorted().toList(), true);
        }
        List<INFO> result = infosForRequest(filterContext)
                .filter(r -> {
                    if (r.createdAt().isAfter(cursor.createdAt())
                            && r.createdAt().isBefore(cursor.snapshotTimestamp())) {
                        return true;
                    }
                    LOG.debugf("Skip %s [%s] for %s", r.getClass().getSimpleName(), r.name(), cursor);
                    return false;
                })
                .sorted()
                // (pageSize + 1) so that we know if a next page exists
                .limit(pageSize + 1)
                .toList();
        if (result.size() > pageSize) {
            return new Page<>(result.subList(0, result.size() - 1), false);
        }
        return new Page<>(result, true);
    }

    Stream<INFO> infosForRequest(FilterContextImpl filterContext) {
