    /**
     * Finds a unique info by name across all servers. Throws {@link IllegalStateException} if multiple distinct infos with the
     * given name exist on different servers.
     *
     * @return the info or {@code null}
     */
    protected static <INFO extends FeatureInfo> INFO findUniqueByName(ConcurrentMap<FeatureKey, INFO> map, String name,
            Feature feature) {
        Objects.requireNonNull(name);
        List<INFO> matches = map.entrySet().stream()
                .filter(e -> e.getKey().name().equals(name))
                .map(Map.Entry::getValue)
                .distinct()
                .toList();
        if (matches.size() > 1) {
            throw new IllegalStateException(
                    "Multiple %s definitions with name [%s] found on different servers; use the method variant that accepts a server name"
                            .formatted(feature, name));
        }
        return matches.isEmpty() ? null : matches.get(0);
    }

    protected Map<Type, DefaultValueConverter<?>> defaultValueConverters() {
        return Map.of();
    }

    Object convert(String value, Type type) {
        return convert(value, type, defaultValueConverters());
    }

    static Object convert(String value, Type type, Map<Type, DefaultValueConverter<?>> defaultValueConverters) {
        if (String.class.equals(type)) {
            return value;
        }
        type = box(type);
        DefaultValueConverter<?> converter = defaultValueConverters.get(type);
        if (converter != null) {
            return converter.convert(value);
        }
        if (type instanceof Class clazz) {
            if (clazz.isEnum()) {
                for (Object constant : clazz.getEnumConstants()) {
                    if (constant.toString().equalsIgnoreCase(value)) {
                        return constant;
                    }
                }
            }
        }
        throw new IllegalArgumentException(
                "Unable to convert the default value for argument type [" + type
                        + "] - provide a custom converter implementation");
    }

    static Type box(Type type) {
        if (type instanceof Class clazz) {
            if (!clazz.isPrimitive()) {
                return type;
            } else if (clazz.equals(Boolean.TYPE)) {
                return Boolean.class;
            } else if (clazz.equals(Character.TYPE)) {
                return Character.class;
            } else if (clazz.equals(Byte.TYPE)) {
                return Byte.class;
            } else if (clazz.equals(Short.TYPE)) {
                return Short.class;
            } else if (clazz.equals(Integer.TYPE)) {
                return Integer.class;
            } else if (clazz.equals(Long.TYPE)) {
                return Long.class;
            } else if (clazz.equals(Float.TYPE)) {
                return Float.class;
            } else if (clazz.equals(Double.TYPE)) {
                return Double.class;
            }
        }
        return type;
    }

