package io.quarkiverse.mcp.server.runtime;

import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentMap;
import java.util.function.Function;
import java.util.function.Predicate;
import java.util.stream.Stream;

import jakarta.enterprise.inject.Instance;
import jakarta.inject.Singleton;

import com.fasterxml.jackson.databind.ObjectMapper;

import io.quarkiverse.mcp.server.JsonRpcErrorCodes;
import io.quarkiverse.mcp.server.McpException;
import io.quarkiverse.mcp.server.McpLog;
import io.quarkiverse.mcp.server.McpMethod;
import io.quarkiverse.mcp.server.Notification;
import io.quarkiverse.mcp.server.Notification.Type;
import io.quarkiverse.mcp.server.NotificationManager;
import io.quarkiverse.mcp.server.NotificationManager.NotificationInfo;
import io.quarkiverse.mcp.server.runtime.config.McpServersRuntimeConfig;
import io.quarkus.security.identity.CurrentIdentityAssociation;
import io.smallrye.mutiny.Uni;
import io.vertx.core.Vertx;
import io.vertx.core.json.JsonObject;

@Singleton
public class NotificationManagerImpl extends FeatureManagerBase<Void, NotificationInfo> implements NotificationManager {

    final ConcurrentMap<FeatureKey, NotificationInfo> notifications;

    NotificationManagerImpl(McpMetadata metadata,
            Vertx vertx,
            ObjectMapper mapper,
            ConnectionManager connectionManager,
            Instance<CurrentIdentityAssociation> currentIdentityAssociation,
            ResponseHandlers responseHandlers,
            CancellationRequests cancellationRequests,
            McpServersRuntimeConfig config) {
        super(vertx, mapper, connectionManager, currentIdentityAssociation, responseHandlers, cancellationRequests, config,
                metadata);
        this.notifications = new ConcurrentHashMap<>();
        for (FeatureMetadata<Void> notification : metadata.notifications()) {
            NotificationMethod notificationMethod = new NotificationMethod(notification);
            String compositeKey = key(notificationMethod);
            for (String server : notification.info().serverNames()) {
                this.notifications.put(new FeatureKey(compositeKey, server), notificationMethod);
            }
        }
    }

    @Override
    Stream<NotificationInfo> infos() {
        return notifications.values().stream().distinct();
    }

    @SuppressWarnings("unchecked")
    @Override
    protected FeatureInvoker<Void> getInvoker(String id, McpRequest mcpRequest, JsonObject message) {
        NotificationInfo init = notifications.get(new FeatureKey(id, mcpRequest.serverName()));
        if (init instanceof FeatureInvoker fi) {
            return fi;
        }
        return null;
    }

    @Override
    protected ArgumentProviders argProviders(JsonObject message, McpRequest mcpRequest, JsonObject arguments) {
        Sender sender = mcpRequest.sender();
        McpMethod method = McpMethod.from(message.getString("method"));
        if (McpMethod.NOTIFICATIONS_INITIALIZED == method) {
            // For notifications/initialized we always use the connection as a sender
            sender = mcpRequest.connection();
        }
        return new ArgumentProviders(message, Map.of(), mcpRequest.connection(), null, null,
                sender, null, responseHandlers, mcpRequest.serverName(), cancellationRequests);
    }

    @Override
    public NotificationInfo getNotification(Type type, String name, String serverName) {
        return notifications.get(new FeatureKey(key(type, name), serverName));
    }

    @Override
    public NotificationInfo getNotification(Type type, String name) {
        return findUniqueByName(notifications, key(type, name), Feature.NOTIFICATION);
    }

    @Override
    public NotificationDefinition newNotification(String name) {
        return new NotificationDefinitionImpl(name);
    }

    @Override
    public boolean removeNotification(Predicate<NotificationInfo> filter) {
        return notifications.entrySet().removeIf(e -> filter.test(e.getValue()));
    }

    IllegalArgumentException notificationAlreadyExists(Type type, String name, String serverName) {
        return new IllegalArgumentException(
                "A " + type + " notification with name [" + name + "] already exists for server configuration [" + serverName
                        + "]");
    }

    @Override
    protected McpException notFound(String id) {
        return new McpException("Invalid notification name: " + id, JsonRpcErrorCodes.INVALID_PARAMS);
    }

    class NotificationMethod extends FeatureMetadataInvoker<Void> implements NotificationManager.NotificationInfo {

        private final Notification.Type type;

        private NotificationMethod(FeatureMetadata<Void> metadata) {
            super(metadata, null);
            this.type = Notification.Type
                    .valueOf(metadata.info().description());
        }

        @Override
        public Type type() {
            return type;
        }

        @Override
        public String name() {
            return metadata.info().name();
        }

        @Override
        public String description() {
            return metadata.info().description();
        }

        @Override
        public Set<String> serverNames() {
            return metadata.info().serverNames();
        }

        @Override
        public boolean isMethod() {
            return true;
        }

        @Override
        public JsonObject asJson() {
            throw new UnsupportedOperationException();
        }

    }

    class NotificationDefinitionImpl
            extends
            FeatureManagerBase.FeatureDefinitionBase<NotificationInfo, NotificationArguments, Void, NotificationDefinitionImpl>
            implements NotificationManager.NotificationDefinition {

        private Notification.Type type;

        private NotificationDefinitionImpl(String name) {
            super(name, NotificationManagerImpl.this.serverNames);
        }

        @Override
        public NotificationDefinition setType(Type type) {
            this.type = type;
            return this;
        }

        @Override
        public NotificationInfo register() {
            validate(false);
            if (type == null) {
                throw new IllegalStateException("Type must be set");
            }
            NotificationDefinitionInfo ret = new NotificationDefinitionInfo(name, description, serverNames, fun, asyncFun,
                    runOnVirtualThread, type);
            String compositeKey = key(ret);
            List<FeatureKey> keys = FeatureKey.list(compositeKey, serverNames);
            registrationLock.lock();
            try {
                for (FeatureKey key : keys) {
                    if (notifications.containsKey(key)) {
                        throw notificationAlreadyExists(type, name, key.serverName());
                    }
                }
                for (FeatureKey key : keys) {
                    notifications.put(key, ret);
                }
            } finally {
                registrationLock.unlock();
            }
            return ret;
        }
    }

    class NotificationDefinitionInfo extends FeatureManagerBase.FeatureDefinitionInfoBase<NotificationArguments, Void>
            implements NotificationManager.NotificationInfo {

        private final Notification.Type type;

        private NotificationDefinitionInfo(String name, String description, Set<String> serverNames,
                Function<NotificationArguments, Void> fun,
                Function<NotificationArguments, Uni<Void>> asyncFun, boolean runOnVirtualThread, Notification.Type type) {
            super(name, description, serverNames, fun, asyncFun, runOnVirtualThread, null);
            this.type = type;
        }

        @Override
        public Type type() {
            return type;
        }

        @Override
        public JsonObject asJson() {
            throw new UnsupportedOperationException();
        }

        @Override
        protected NotificationArguments createArguments(ArgumentProviders argumentProviders) {
            return new NotificationArgumentsImpl(argumentProviders,
                    log(Feature.NOTIFICATION.toString().toLowerCase() + ":" + name, name, argumentProviders));
        }

    }

    static class NotificationArgumentsImpl extends AbstractFeatureArguments implements NotificationArguments {

        private final McpLog log;

        NotificationArgumentsImpl(ArgumentProviders argProviders, McpLog log) {
            super(argProviders);
            this.log = log;
        }

        @Override
        public McpLog log() {
            return log;
        }

    }

    public String key(NotificationInfo info) {
        return key(info.type(), info.name());
    }

    private String key(Type type, String name) {
        return Objects.requireNonNull(type) + "::" + Objects.requireNonNull(name);
    }

}


